# Generated by: Agent 3 (Supertrend)
#!/usr/bin/env python3
"""
Experiment #9894: 1h Supertrend Trend Following with Volume and Session Filter
Hypothesis: Supertrend indicator captures trend direction effectively. Combined with volume confirmation 
and restricted to active trading hours (08-20 UTC), this strategy should work in both bull and bear 
markets by following established trends while avoiding false signals during low-volume periods.
Uses 1d timeframe for trend filter to reduce noise and keep trade frequency within target (15-37/year).
"""

import numpy as np
import pandas as pd
from mtf_data import get_htf_data, align_htf_to_ltf

name = "exp_9894_1h_supertrend_volume_session_v1"
timeframe = "1h"
leverage = 1.0

# Parameters
SUPERTREND_PERIOD = 10
SUPERTREND_MULTIPLIER = 3.0
VOLUME_SPIKE_MULTIPLIER = 1.5
SIGNAL_SIZE = 0.20
ATR_PERIOD = 10

def calculate_atr(high, low, close, period):
    """Calculate ATR using Wilder's smoothing"""
    tr1 = high - low
    tr2 = np.abs(high - np.roll(close, 1))
    tr3 = np.abs(low - np.roll(close, 1))
    tr = np.maximum(np.maximum(tr1, tr2), tr3)
    atr = pd.Series(tr).ewm(alpha=1/period, adjust=False, min_periods=period).mean().values
    return atr

def calculate_supertrend(high, low, close, period, multiplier):
    """Calculate Supertrend indicator"""
    atr = calculate_atr(high, low, close, period)
    
    # Basic upper and lower bands
    hl_avg = (high + low) / 2
    upper_band = hl_avg + (multiplier * atr)
    lower_band = hl_avg - (multiplier * atr)
    
    # Initialize final bands
    final_upper_band = np.full_like(close, np.nan)
    final_lower_band = np.full_like(close, np.nan)
    
    # Calculate final bands
    for i in range(len(close)):
        if i == 0:
            final_upper_band[i] = upper_band[i]
            final_lower_band[i] = lower_band[i]
        else:
            if upper_band[i] < final_upper_band[i-1] or close[i-1] > final_upper_band[i-1]:
                final_upper_band[i] = upper_band[i]
            else:
                final_upper_band[i] = final_upper_band[i-1]
                
            if lower_band[i] > final_lower_band[i-1] or close[i-1] < final_lower_band[i-1]:
                final_lower_band[i] = lower_band[i]
            else:
                final_lower_band[i] = final_lower_band[i-1]
    
    # Determine trend direction
    supertrend = np.full_like(close, np.nan)
    for i in range(len(close)):
        if i == 0:
            supertrend[i] = final_lower_band[i]
        else:
            if supertrend[i-1] == final_upper_band[i-1]:
                if close[i] <= final_upper_band[i]:
                    supertrend[i] = final_upper_band[i]
                else:
                    supertrend[i] = final_lower_band[i]
            else:
                if close[i] >= final_lower_band[i]:
                    supertrend[i] = final_lower_band[i]
                else:
                    supertrend[i] = final_upper_band[i]
    
    # Trend direction: 1 for uptrend, -1 for downtrend
    trend = np.where(close > supertrend, 1, -1)
    return trend, supertrend

def generate_signals(prices):
    n = len(prices)
    if n < 50:
        return np.zeros(n)
    
    # Load daily data ONCE before loop for trend filter
    df_daily = get_htf_data(prices, '1d')
    
    # Calculate daily Supertrend for trend direction
    daily_high = df_daily['high'].values
    daily_low = df_daily['low'].values
    daily_close = df_daily['close'].values
    daily_trend, _ = calculate_supertrend(daily_high, daily_low, daily_close, SUPERTREND_PERIOD, SUPERTREND_MULTIPLIER)
    
    # Align daily trend to 1h timeframe
    daily_trend_aligned = align_htf_to_ltf(prices, df_daily, daily_trend)
    
    # Calculate 1h indicators
    high = prices['high'].values
    low = prices['low'].values
    close = prices['close'].values
    volume = prices['volume'].values
    
    # ATR for Supertrend calculation
    atr = calculate_atr(high, low, close, ATR_PERIOD)
    
    # Volume moving average for spike detection
    volume_ma = pd.Series(volume).rolling(window=20, min_periods=20).mean().values
    
    # Calculate 1h Supertrend
    h1_trend, _ = calculate_supertrend(high, low, close, SUPERTREND_PERIOD, SUPERTREND_MULTIPLIER)
    
    # Session filter: 08-20 UTC (active trading hours)
    hours = prices.index.hour
    
    signals = np.zeros(n)
    position = 0  # 0: flat, 1: long, -1: short
    entry_price = 0.0
    stop_price = 0.0
    
    # Start from warmup period
    start = max(SUPERTREND_PERIOD * 2, 20) + 1
    
    for i in range(start, n):
        # Skip if daily trend not available
        if np.isnan(daily_trend_aligned[i]):
            signals[i] = position * SIGNAL_SIZE if position != 0 else 0.0
            continue
            
        # Session filter: only trade during active hours (08-20 UTC)
        hour = hours[i]
        if not (8 <= hour <= 20):
            if position != 0:
                signals[i] = 0.0
                position = 0
            else:
                signals[i] = 0.0
            continue
        
        # Volume spike confirmation
        volume_spike = volume[i] > (volume_ma[i] * VOLUME_SPIKE_MULTIPLIER) if not np.isnan(volume_ma[i]) else False
        
        # Check stoploss (2 * ATR)
        if position == 1:  # long position
            if close[i] <= stop_price:
                signals[i] = 0.0
                position = 0
                continue
        elif position == -1:  # short position
            if close[i] >= stop_price:
                signals[i] = 0.0
                position = 0
                continue
        
        # Entry conditions: Supertrend alignment with volume spike
        long_entry = (h1_trend[i] == 1) and (daily_trend_aligned[i] == 1) and volume_spike
        short_entry = (h1_trend[i] == -1) and (daily_trend_aligned[i] == -1) and volume_spike
        
        # Generate signals
        if position == 0:
            if long_entry:
                signals[i] = SIGNAL_SIZE
                position = 1
                entry_price = close[i]
                stop_price = entry_price - (2.0 * atr[i])
            elif short_entry:
                signals[i] = -SIGNAL_SIZE
                position = -1
                entry_price = close[i]
                stop_price = entry_price + (2.0 * atr[i])
            else:
                signals[i] = 0.0
        elif position == 1:
            signals[i] = SIGNAL_SIZE
        elif position == -1:
            signals[i] = -SIGNAL_SIZE
    
    return signals